$content = Get-Content -Path $args[0] -Encoding UTF8 -Raw
$old = "`n                    val purchaseRepo = PurchaseRepository(context)`n                    val supplierName = selectedSupplier.substringAfter(`"| `").trim()`n                    val orderNo = `"PO-`${LocalDate.now().toString().replace(`"-`", `"`")}-`${System.currentTimeMillis() % 100000}`"`n                    val qty = quantity.toDoubleOrNull() ?: 1.0`n                    val price = unitPrice.toDoubleOrNull() ?: 0.0`n                    val total = qty * price`n                    purchaseRepo.insert(orderNo, supplierName, orderDate, total, `"draft`", note)`n                    withContext(Dispatchers.Main) { onSaved(); onDismiss() }"
$new = "`n                    val productRepo = ProductRepository(context)`n                    val purchaseRepo = PurchaseRepository(context)`n                    val productCode = selectedProduct.substringBefore(`" |`")`n                    val supplierName = selectedSupplier.substringAfter(`"| `").trim()`n                    val orderNo = `"PO-`${LocalDate.now().toString().replace(`"-`", `"`")}-`${System.currentTimeMillis() % 100000}`"`n                    val qty = quantity.toDoubleOrNull() ?: 1.0`n                    val price = unitPrice.toDoubleOrNull() ?: 0.0`n                    val total = qty * price`n                    val orderId = purchaseRepo.insert(orderNo, supplierName, orderDate, total, `"draft`", note)`n                    val products = productRepo.searchProducts(productCode)`n                    val product = products.firstOrNull()`n                    if (product != null && product.id > 0) {`n                        purchaseRepo.insertItem(orderId, product.id, qty, price, product.barcode, product.unit)`n                    }`n                    withContext(Dispatchers.Main) { onSaved(); onDismiss() }"
$content = $content.Replace($old, $new)
[System.IO.File]::WriteAllText($args[0], $content, [System.Text.UTF8Encoding]::new(`$false))
